// Created: 2026-03-26

/**
 * TaskCreated Hook: Context Injector
 *
 * Enriches newly created tasks with project context (current branch, recent commits).
 * Injects advisory via additionalContext so Claude has branch awareness when working on tasks.
 *
 * @hook TaskCreated
 * @since CC 2.1.84
 */

import type { HookInput, HookResult } from '../types.js';
import { logHook, outputSilentSuccess } from '../lib/common.js';
import { execSync } from 'node:child_process';

const HOOK_NAME = 'task-context-injector';

function getCurrentBranch(): string | null {
  try {
    return execSync('git rev-parse --abbrev-ref HEAD', {
      encoding: 'utf8',
      timeout: 3000,
      stdio: ['pipe', 'pipe', 'pipe'],
    }).trim();
  } catch {
    return null;
  }
}

function getRecentCommitSubject(): string | null {
  try {
    return execSync('git log -1 --format=%s', {
      encoding: 'utf8',
      timeout: 3000,
      stdio: ['pipe', 'pipe', 'pipe'],
    }).trim();
  } catch {
    return null;
  }
}

export function taskContextInjector(input: HookInput): HookResult {
  const taskSubject = input.task_subject || '';
  if (!taskSubject) return outputSilentSuccess();

  const branch = getCurrentBranch();
  if (!branch) return outputSilentSuccess();

  const lastCommit = getRecentCommitSubject();
  const parts = [`Branch: ${branch}`];
  if (lastCommit) parts.push(`Last commit: ${lastCommit}`);

  logHook(HOOK_NAME, `Injecting context for task: ${taskSubject}`);

  return {
    continue: true,
    hookSpecificOutput: {
      additionalContext: `[TaskCreated] ${parts.join(' | ')}`,
    },
  };
}
